  created_at timestamptz NOT NULL DEFAULT NOW(),
  UNIQUE (company_id, event_type, source_event_uuid)
);

CREATE INDEX idx_ingest_event_keys_lookup
  ON ingest_event_keys(company_id, event_type, created_at DESC);
