-- >>> BEGIN MIGRATION: 20260404000200_realtime_publication_tables.sql
-- ========================================================
-- Migration: 20260404000200_realtime_publication_tables
-- Purpose:   Register app tables with Supabase Realtime publication.
--            Without these entries, postgres_changes subscriptions
--            never receive inserts/updates from the local database.
-- ========================================================

DO $$
DECLARE
  realtime_table text;
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM pg_publication
    WHERE pubname = 'supabase_realtime'
  ) THEN
    RAISE NOTICE 'supabase_realtime publication does not exist; skipping registration';
    RETURN;
  END IF;

  FOREACH realtime_table IN ARRAY ARRAY[
    'public.clock_events',
    'public.photo_events',
    'public.task_events',
    'public.note_events',
    'public.ot_approval_events',
    'public.correction_events',
    'public.users',
    'public.jobs'
  ]
  LOOP
    IF NOT EXISTS (
      SELECT 1
      FROM pg_publication_tables
      WHERE pubname = 'supabase_realtime'
        AND schemaname = split_part(realtime_table, '.', 1)
        AND tablename = split_part(realtime_table, '.', 2)
    ) THEN
      EXECUTE format('ALTER PUBLICATION supabase_realtime ADD TABLE %s', realtime_table);
    END IF;
  END LOOP;
END $$;
-- <<< END MIGRATION: 20260404000200_realtime_publication_tables.sql

-- >>> BEGIN MIGRATION: 20260404000300_realtime_partition_root.sql
-- ========================================================
-- Migration: 20260404000300_realtime_partition_root
-- Purpose:   Publish partitioned event changes via their parent table names
--            so Supabase Realtime subscriptions on clock_events/photo_events/
--            task_events/etc. receive inserts from partition children.
-- ========================================================

ALTER PUBLICATION supabase_realtime
SET (publish_via_partition_root = true);
-- <<< END MIGRATION: 20260404000300_realtime_partition_root.sql

