-- >>> BEGIN MIGRATION: 20260405000000_security_rls_fixes.sql
-- ========================================================
-- Migration: 20260405000000_security_rls_fixes
-- Purpose:   Code review P0/P2 security hardening
--            - Enable RLS on api_guard tables (were fully unprotected)
--            - Add write policies for schedule_shifts (INSERT/UPDATE/DELETE)
--            - Add UPDATE policy for expense_events (approval workflow)
--            - Add INSERT policies for task_events and note_events
--            - Add missing indexes on ot_requests
-- ========================================================

-- ========================================================
-- 1. Enable RLS on api_guard tables
--    These tables hold sensitive per-user request history.
-- ========================================================

ALTER TABLE api_idempotency_keys ENABLE ROW LEVEL SECURITY;
ALTER TABLE api_request_logs ENABLE ROW LEVEL SECURITY;
ALTER TABLE ingest_event_keys ENABLE ROW LEVEL SECURITY;

-- api_idempotency_keys: users can only see their own records
CREATE POLICY "User isolation for api_idempotency_keys"
ON api_idempotency_keys
FOR SELECT
USING (user_id = auth.uid());

-- api_request_logs: users can only see their own records
CREATE POLICY "User isolation for api_request_logs"
ON api_request_logs
FOR SELECT
USING (user_id = auth.uid());

-- ingest_event_keys: restricted to service role only (edge functions bypass RLS).
-- No client-facing SELECT policy — these are internal dedup records.

-- ========================================================
-- 2. schedule_shifts write policies
--    Supervisors and admins can INSERT/UPDATE/DELETE.
--    Workers can only SELECT (already covered by tenant isolation policy).
-- ========================================================

CREATE POLICY "Supervisor schedule insert"
ON schedule_shifts
FOR INSERT
WITH CHECK (
  company_id = public.current_company_id()
  AND public.current_user_role() IN ('supervisor', 'admin')
  AND created_by = auth.uid()
);

CREATE POLICY "Supervisor schedule update"
ON schedule_shifts
FOR UPDATE
USING (
  company_id = public.current_company_id()
  AND public.current_user_role() IN ('supervisor', 'admin')
)
WITH CHECK (
  company_id = public.current_company_id()
  AND public.current_user_role() IN ('supervisor', 'admin')
);

CREATE POLICY "Supervisor schedule delete"
ON schedule_shifts
FOR DELETE
USING (
  company_id = public.current_company_id()
  AND public.current_user_role() IN ('supervisor', 'admin')
  AND status = 'draft'  -- cannot delete published shifts
);

-- ========================================================
-- 3. expense_events UPDATE policy (approval workflow)
--    Only supervisors/admins for the same company can update
--    (approve/deny/reimburse). Workers cannot modify their own decisions.
-- ========================================================

CREATE POLICY "Supervisor expense approval update"
ON expense_events
FOR UPDATE
USING (
  company_id = public.current_company_id()
  AND public.current_user_role() IN ('supervisor', 'admin')
  AND submitted_by != auth.uid()  -- cannot approve own expense
)
WITH CHECK (
  company_id = public.current_company_id()
  AND public.current_user_role() IN ('supervisor', 'admin')
  AND submitted_by != auth.uid()
);

-- ========================================================
-- 4. task_events and note_events INSERT policies
--    Edge functions (service role) handle most writes, but
--    adding client-side policies prevents unintentional gaps.
-- ========================================================

CREATE POLICY "Worker task event insert"
ON task_events
FOR INSERT
WITH CHECK (
  company_id = public.current_company_id()
  AND user_id = auth.uid()
);

CREATE POLICY "Worker note event insert"
ON note_events
FOR INSERT
WITH CHECK (
  company_id = public.current_company_id()
  AND author_id = auth.uid()
);

-- ========================================================
-- 5. Missing indexes on ot_requests
--    worker_id and company_id are used in every OT query.
-- ========================================================

CREATE INDEX IF NOT EXISTS idx_ot_requests_worker_id
  ON ot_requests(worker_id);

CREATE INDEX IF NOT EXISTS idx_ot_requests_company_status
  ON ot_requests(company_id, status, requested_at DESC);
-- <<< END MIGRATION: 20260405000000_security_rls_fixes.sql

-- >>> BEGIN MIGRATION: 20260405100000_pto_requests.sql
-- PTO / Time-Off Requests
-- Workers submit vacation/sick/personal leave requests.
-- Supervisors approve or deny.
-- Approved PTO deducts from available balance (tracked per company year).

CREATE TABLE IF NOT EXISTS pto_requests (
    id              uuid        NOT NULL DEFAULT gen_random_uuid(),
    company_id      uuid        NOT NULL REFERENCES companies(id),
    user_id         uuid        NOT NULL REFERENCES users(id),
    pto_type        text        NOT NULL CHECK (pto_type IN ('vacation', 'sick', 'personal')),
    start_date      date        NOT NULL,
    end_date        date        NOT NULL,
    day_count       int         NOT NULL GENERATED ALWAYS AS (end_date - start_date + 1) STORED,
    status          text        NOT NULL DEFAULT 'pending' CHECK (status IN ('pending', 'approved', 'denied', 'cancelled')),
    notes           text,
    decided_by      uuid        REFERENCES users(id),
    decided_at      timestamptz,
    decision_reason text,
    created_at      timestamptz NOT NULL DEFAULT now(),
    updated_at      timestamptz NOT NULL DEFAULT now(),

    CONSTRAINT pto_dates_valid CHECK (end_date >= start_date),
    PRIMARY KEY (id)
);

-- Indexes for common query patterns
CREATE INDEX IF NOT EXISTS idx_pto_requests_user ON pto_requests(user_id, status, start_date DESC);
CREATE INDEX IF NOT EXISTS idx_pto_requests_company ON pto_requests(company_id, status, start_date DESC);

-- RLS
ALTER TABLE pto_requests ENABLE ROW LEVEL SECURITY;

-- Workers see their own PTO requests
CREATE POLICY "Worker sees own PTO"
    ON pto_requests FOR SELECT
    USING (company_id = public.current_company_id());

-- Workers can insert their own PTO requests
CREATE POLICY "Worker PTO insert"
    ON pto_requests FOR INSERT
    WITH CHECK (
        company_id = public.current_company_id()
        AND user_id = auth.uid()
        AND status = 'pending'
    );

-- Workers can cancel their own pending requests
CREATE POLICY "Worker PTO cancel"
    ON pto_requests FOR UPDATE
    USING (
        company_id = public.current_company_id()
        AND user_id = auth.uid()
        AND status = 'pending'
    )
    WITH CHECK (status = 'cancelled');

-- Supervisors/admins can approve or deny
CREATE POLICY "Supervisor PTO decision"
    ON pto_requests FOR UPDATE
    USING (
        company_id = public.current_company_id()
        AND public.current_user_role() IN ('supervisor', 'admin')
        AND status = 'pending'
    )
    WITH CHECK (
        status IN ('approved', 'denied')
        AND decided_by = auth.uid()
    );
-- <<< END MIGRATION: 20260405100000_pto_requests.sql

-- >>> BEGIN MIGRATION: 20260406000000_admin_system.sql
-- ═══════════════════════════════════════════════════════════
-- Admin System: Company Management, Platform Admin, Audit Trail
-- ═══════════════════════════════════════════════════════════

-- ─── 1. Extend companies table ──────────────────────────────

ALTER TABLE companies ADD COLUMN IF NOT EXISTS industry text;
ALTER TABLE companies ADD COLUMN IF NOT EXISTS address text;
ALTER TABLE companies ADD COLUMN IF NOT EXISTS phone text;
ALTER TABLE companies ADD COLUMN IF NOT EXISTS email text;
ALTER TABLE companies ADD COLUMN IF NOT EXISTS stripe_customer_id text;
ALTER TABLE companies ADD COLUMN IF NOT EXISTS payment_status text NOT NULL DEFAULT 'trialing';
ALTER TABLE companies ADD COLUMN IF NOT EXISTS logo_data_uri text;
ALTER TABLE companies ADD COLUMN IF NOT EXISTS settings_version int NOT NULL DEFAULT 1;
ALTER TABLE companies ADD COLUMN IF NOT EXISTS billing_mode text NOT NULL DEFAULT 'demo';

-- Constraint: payment_status values
ALTER TABLE companies DROP CONSTRAINT IF EXISTS chk_payment_status;
ALTER TABLE companies ADD CONSTRAINT chk_payment_status
  CHECK (payment_status IN ('trialing', 'active', 'past_due', 'cancelled'));
ALTER TABLE companies DROP CONSTRAINT IF EXISTS chk_billing_mode;
ALTER TABLE companies ADD CONSTRAINT chk_billing_mode
  CHECK (billing_mode IN ('demo', 'stripe'));

-- ─── 2. Admin UPDATE policies for companies and users ───────

-- Company owner/admin can update their own company
CREATE POLICY "Admin company update"
  ON companies FOR UPDATE
  USING (id = public.current_company_id() AND public.current_user_role() IN ('owner', 'admin'))
  WITH CHECK (id = public.current_company_id());

-- Company owner/admin can update users within their company
CREATE POLICY "Admin user update"
  ON users FOR UPDATE
  USING (
    company_id = public.current_company_id()
    AND (
      public.current_user_role() = 'owner'
      OR (public.current_user_role() = 'admin' AND role <> 'owner')
    )
  )
  WITH CHECK (
    company_id = public.current_company_id()
    AND (
      public.current_user_role() = 'owner'
      OR (public.current_user_role() = 'admin' AND role <> 'owner')
    )
  );

-- ─── 3. Platform admins table (FieldOps internal staff) ─────

CREATE TABLE IF NOT EXISTS platform_admins (
  id           uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  auth_user_id uuid        NOT NULL UNIQUE REFERENCES auth.users(id) ON DELETE CASCADE,
  email        text        NOT NULL,
  full_name    text        NOT NULL,
  role         text        NOT NULL DEFAULT 'platform_admin',
  is_active    boolean     NOT NULL DEFAULT true,
  created_at   timestamptz NOT NULL DEFAULT NOW(),
  updated_at   timestamptz NOT NULL DEFAULT NOW()
);

-- No RLS on platform_admins — accessed only via service role key
-- from the super-admin app.

-- ─── 4. Platform admin invites ──────────────────────────────

CREATE TABLE IF NOT EXISTS platform_admin_invites (
  id           uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  email        text        NOT NULL,
  invite_token text        NOT NULL UNIQUE DEFAULT encode(gen_random_bytes(32), 'hex'),
  expires_at   timestamptz NOT NULL DEFAULT (NOW() + INTERVAL '7 days'),
  claimed_at   timestamptz,
  created_by   uuid        REFERENCES platform_admins(id),
  created_at   timestamptz NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_platform_admin_invites_token
  ON platform_admin_invites(invite_token) WHERE claimed_at IS NULL;

-- ─── 5. Admin audit log (SOC2/GDPR compliant) ──────────────

CREATE TABLE IF NOT EXISTS admin_audit_log (
  id               uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  company_id       uuid        REFERENCES companies(id),
  actor_id         uuid,  -- could be company user or platform admin
  action           text        NOT NULL,
  target_type      text,  -- 'user', 'company', 'settings', 'invite', etc.
  target_id        text,  -- UUID or identifier of the target
  before_json      jsonb,
  after_json       jsonb,
  settings_version int,
  ip_address       text,
  user_agent       text,
  created_at       timestamptz NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_audit_log_company
  ON admin_audit_log(company_id, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_audit_log_actor
  ON admin_audit_log(actor_id, created_at DESC);

-- No RLS — service-role-only access from edge functions.

-- ─── 6. Company summary view (for super-admin dashboard) ────

CREATE OR REPLACE VIEW company_summary AS
SELECT
  c.id,
  c.name,
  c.slug,
  c.status,
  c.payment_status,
  c.industry,
  c.logo_url,
  c.created_at,
  c.updated_at,
  COUNT(u.id) FILTER (WHERE u.is_active AND u.deleted_at IS NULL) AS active_user_count,
  COUNT(u.id) FILTER (WHERE u.deleted_at IS NULL) AS total_user_count
FROM companies c
LEFT JOIN users u ON u.company_id = c.id
WHERE c.deleted_at IS NULL
GROUP BY c.id;

-- ─── 7. Helper: is_platform_admin() ────────────────────────

CREATE OR REPLACE FUNCTION public.is_platform_admin()
RETURNS boolean
LANGUAGE sql SECURITY DEFINER SET search_path = public STABLE AS $$
  SELECT EXISTS (
    SELECT 1 FROM platform_admins
    WHERE auth_user_id = auth.uid() AND is_active = true
  )
$$;

