-- Helper: compute per-(job, user) clock_in -> clock_out durations in minutes.
-- clock_events is append-only event-sourced with no duration column; we pair
-- each clock_out with the immediately preceding clock_in for the same user
-- on the same job (matches the pairing logic in the timecards edge function).
CREATE OR REPLACE VIEW job_clock_durations AS
WITH clock_pairs AS (
  SELECT
    ce.job_id,
    ce.user_id,
    ce.event_subtype,
    ce.occurred_at,
    LAG(ce.occurred_at) OVER (
      PARTITION BY ce.job_id, ce.user_id
      ORDER BY ce.occurred_at
    ) AS prev_occurred_at,
    LAG(ce.event_subtype) OVER (
      PARTITION BY ce.job_id, ce.user_id
      ORDER BY ce.occurred_at
    ) AS prev_subtype
  FROM clock_events ce
)
SELECT
  job_id,
  user_id,
  EXTRACT(EPOCH FROM (occurred_at - prev_occurred_at)) / 60.0 AS minutes
FROM clock_pairs
WHERE event_subtype = 'clock_out'
  AND prev_subtype   = 'clock_in'
  AND prev_occurred_at IS NOT NULL;

-- View for budget vs actual reporting
CREATE VIEW job_budget_summary AS
SELECT
  jb.id,
  jb.company_id,
  jb.job_id,
  j.name AS job_name,
  j.code AS job_code,
  j.status AS job_status,
  jb.budgeted_hours,
  jb.budgeted_cost,
  jb.hourly_rate,
  jb.warning_threshold_percent,
  COALESCE(agg.actual_hours, 0) AS actual_hours,
  COALESCE(agg.actual_hours, 0) * jb.hourly_rate AS actual_cost,
  jb.created_by,
  jb.created_at,
  jb.updated_at
FROM job_budgets jb
JOIN jobs j ON j.id = jb.job_id
LEFT JOIN LATERAL (
  SELECT COALESCE(SUM(d.minutes), 0) / 60.0 AS actual_hours
  FROM job_clock_durations d
  WHERE d.job_id = jb.job_id
) agg ON true;

-- Function to calculate job labor costs
CREATE OR REPLACE FUNCTION calculate_job_labor_cost(p_job_id uuid)
RETURNS TABLE (
  actual_hours numeric,
  actual_cost numeric,
  worker_count bigint
) AS $$
DECLARE
  v_hourly_rate numeric;
BEGIN
  SELECT jb.hourly_rate INTO v_hourly_rate
  FROM job_budgets jb
  WHERE jb.job_id = p_job_id;

  v_hourly_rate := COALESCE(v_hourly_rate, 0);

  RETURN QUERY
  SELECT
    COALESCE(SUM(d.minutes) / 60.0, 0)::numeric           AS actual_hours,
    (COALESCE(SUM(d.minutes) / 60.0, 0) * v_hourly_rate)::numeric AS actual_cost,
    COUNT(DISTINCT d.user_id)                              AS worker_count
  FROM job_clock_durations d
  WHERE d.job_id = p_job_id;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;
-- <<< END MIGRATION: 20260408000000_job_budgets.sql

-- >>> BEGIN MIGRATION: 20260408000001_time_corrections.sql
-- ========================================================-- Migration: 20260408000001_time_corrections-- Purpose:   Add manual time entry corrections with audit trail-- =========================================================

CREATE TABLE time_corrections (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  company_id uuid NOT NULL REFERENCES companies(id) ON DELETE RESTRICT,
  worker_id uuid NOT NULL REFERENCES users(id) ON DELETE RESTRICT,
  job_id uuid NOT NULL REFERENCES jobs(id) ON DELETE CASCADE,

  -- The corrected event (what we're fixing).
  -- Note: clock_events is RANGE-partitioned on occurred_at with composite
  -- PK (id, occurred_at). Postgres does not allow a FOREIGN KEY that
  -- references only `id`, so we store the event identifier as a plain
  -- uuid. Referential integrity is enforced at write time by the
  -- time_corrections edge function which looks up the original event.
  original_event_id uuid,
  original_event_subtype clock_event_type,
  original_occurred_at timestamptz,

  -- The corrected values
  corrected_event_subtype clock_event_type NOT NULL,
  corrected_occurred_at timestamptz NOT NULL,

  -- Audit trail
  reason text NOT NULL,
  evidence_notes text,

  -- Who made the correction
  created_by uuid NOT NULL REFERENCES users(id) ON DELETE RESTRICT,
  created_at timestamptz NOT NULL DEFAULT NOW(),

  -- Status for approval workflow
  status approval_decision NOT NULL DEFAULT 'pending',
  decided_by uuid REFERENCES users(id) ON DELETE SET NULL,
  decided_at timestamptz,
  decision_reason text,

  -- Correction creates a new clock_event when approved. Same FK limitation
  -- as original_event_id (partitioned table, composite PK).
  resulting_event_id uuid,

  updated_at timestamptz NOT NULL DEFAULT NOW()
);

CREATE TRIGGER trg_time_corrections_updated_at
BEFORE UPDATE ON time_corrections
FOR EACH ROW EXECUTE FUNCTION set_updated_at();

CREATE INDEX idx_time_corrections_company_status ON time_corrections(company_id, status, created_at DESC);
CREATE INDEX idx_time_corrections_worker ON time_corrections(worker_id, created_at DESC);
CREATE INDEX idx_time_corrections_job ON time_corrections(job_id, created_at DESC);
CREATE INDEX idx_time_corrections_original_event ON time_corrections(original_event_id);

ALTER TABLE time_corrections ENABLE ROW LEVEL SECURITY;

-- Workers can view their own corrections
CREATE POLICY "Workers can view own time_corrections"
ON time_corrections
FOR SELECT
USING (
  company_id = public.current_company_id()
  AND (worker_id = auth.uid() OR created_by = auth.uid())
);

-- Supervisors/admins can view all corrections for their company
CREATE POLICY "Supervisors can view company time_corrections"
ON time_corrections
FOR SELECT
USING (
  company_id = public.current_company_id()
  AND EXISTS (
    SELECT 1 FROM users
    WHERE users.id = auth.uid()
    AND users.role IN ('supervisor', 'admin', 'foreman')
  )
);

-- Supervisors/admins can create corrections
CREATE POLICY "Supervisors can create time_corrections"
ON time_corrections
FOR INSERT
WITH CHECK (
  company_id = public.current_company_id()
  AND EXISTS (
    SELECT 1 FROM users
    WHERE users.id = auth.uid()
    AND users.role IN ('supervisor', 'admin', 'foreman')
  )
);

-- Only supervisors/admins can update (approve/deny)
CREATE POLICY "Supervisors can update time_corrections"
ON time_corrections
FOR UPDATE
USING (
  company_id = public.current_company_id()
  AND EXISTS (
    SELECT 1 FROM users
    WHERE users.id = auth.uid()
    AND users.role IN ('supervisor', 'admin')
  )
);

-- View for time correction summary with worker and job details
CREATE VIEW time_correction_summary AS
SELECT
  tc.*,
  w.full_name AS worker_name,
  j.name AS job_name,
  j.code AS job_code,
  cb.full_name AS created_by_name,
  db.full_name AS decided_by_name
FROM time_corrections tc
JOIN users w ON w.id = tc.worker_id
JOIN jobs j ON j.id = tc.job_id
JOIN users cb ON cb.id = tc.created_by
LEFT JOIN users db ON db.id = tc.decided_by;
-- <<< END MIGRATION: 20260408000001_time_corrections.sql

-- >>> BEGIN MIGRATION: 20260409000000_hardening_bucket_and_admin_rls.sql
-- =========================================================
-- Migration: 20260409000000_hardening_bucket_and_admin_rls
-- Purpose:
--   1. Create the `fieldops-media` storage bucket in hosted
--      environments. Previously only created in seed.sql,
--      which is not applied to hosted Supabase projects.
--   2. Enable RLS (default-deny) on admin tables so they
--      cannot be enumerated via PostgREST by authenticated
--      users. Service role still bypasses RLS automatically.
-- Author:   production-readiness audit, 2026-04-10
-- =========================================================

-- ─── 1. fieldops-media bucket (idempotent) ──────────────────
-- Matches seed.sql defaults: private, 20MB limit, jpg/png only.
-- Upload/read is gated by the storage RLS policies defined in
-- migration 20260404000100_storage_media_policies.sql which
-- scope access by company_id via foldername()[1].

INSERT INTO storage.buckets (id, name, public, file_size_limit, allowed_mime_types)
VALUES (
  'fieldops-media',
  'fieldops-media',
  false,
  20971520,
  ARRAY['image/jpeg', 'image/png']::text[]
)
ON CONFLICT (id) DO UPDATE
SET
  public            = EXCLUDED.public,
  file_size_limit   = EXCLUDED.file_size_limit,
  allowed_mime_types = EXCLUDED.allowed_mime_types,
  updated_at        = NOW();

-- ─── 2. Admin table RLS (default-deny) ──────────────────────
-- These tables are intended for service-role-only access from
-- the platform_admin edge function. Without RLS enabled, they
-- are exposed to authenticated users via PostgREST. Enabling
-- RLS with zero policies = default deny for everyone except
-- service_role (which bypasses RLS).

ALTER TABLE public.platform_admins        ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.platform_admin_invites ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.admin_audit_log        ENABLE ROW LEVEL SECURITY;

-- Explicitly revoke from PostgREST-exposed roles as belt-and-suspenders.
REVOKE ALL ON public.platform_admins        FROM anon, authenticated;
REVOKE ALL ON public.platform_admin_invites FROM anon, authenticated;
REVOKE ALL ON public.admin_audit_log        FROM anon, authenticated;
-- <<< END MIGRATION: 20260409000000_hardening_bucket_and_admin_rls.sql

-- >>> BEGIN MIGRATION: 20260410000000_advisor_hardening.sql
-- =========================================================
-- Migration: 20260410000000_advisor_hardening
-- Purpose:
--   Resolve Supabase security advisor findings after initial
--   24-migration bootstrap:
--
--   1. security_definer_view (ERROR) — views created by a
--      superuser role default to SECURITY DEFINER semantics in
--      Supabase, bypassing RLS for the querying user. Set
--      security_invoker = true on every tenant-facing view so
--      they enforce the caller's RLS policies.
--
--   2. function_search_path_mutable (WARN) — trigger / helper
--      functions without SET search_path are exposed to
--      CVE-2018-1058 if the search_path is ever manipulated.
--      Pin search_path = public on every such function.
--
-- Author: production-readiness audit, 2026-04-10
-- =========================================================

-- ─── 1. Enable security_invoker on tenant-facing views ─────

ALTER VIEW public.job_timeline            SET (security_invoker = true);
ALTER VIEW public.company_summary         SET (security_invoker = true);
ALTER VIEW public.job_clock_durations     SET (security_invoker = true);
ALTER VIEW public.job_budget_summary      SET (security_invoker = true);
ALTER VIEW public.time_correction_summary SET (security_invoker = true);

-- ─── 2. Pin search_path on mutable-search_path functions ──

ALTER FUNCTION public.set_updated_at()                             SET search_path = public;
ALTER FUNCTION public.prevent_event_mutation()                     SET search_path = public;
ALTER FUNCTION public.enqueue_job(p_type text, p_payload jsonb, p_delay interval)
  SET search_path = public;
ALTER FUNCTION public.claim_next_job(p_types text[])                SET search_path = public;
ALTER FUNCTION public.complete_job(p_id uuid, p_error text)         SET search_path = public;
-- <<< END MIGRATION: 20260410000000_advisor_hardening.sql

COMMIT;
